//   - Proper error handling for timeout and execution errors
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Validate input script is not empty
	if conditionScript == "" {
		return nil, errors.New("condition script cannot be empty")
	}

	for _, item := range items {
		vm := otto.New()

		// Set up timeout mechanism to prevent infinite loops (DoS protection)
		timeout := 5 * time.Second
		haltChan := make(chan func(), 1)
		vm.Interrupt = haltChan

		// Create a channel to signal completion
		done := make(chan struct{})

		// Start timeout goroutine
		go func() {
			select {
			case <-time.After(timeout):
				// Timeout reached, interrupt execution
				haltChan <- func() {
					panic(ErrExecutionInterrupted)
				}
			case <-done:
				// Execution completed normally, do nothing
				return
			}
		}()

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			close(done)
			return nil, err
		}

		// Run the condition script with timeout protection
		value, err := vm.Run(conditionScript)

		// Signal completion to stop timeout goroutine
		close(done)

		if err != nil {
			// Check if it was a timeout/interrupt error
			if err.Error() == ErrExecutionInterrupted.Error() || err == ErrExecutionInterrupted {
				return nil, errors.New("script execution timeout: possible infinite loop detected")
			}
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

