// - Input validation for empty scripts
// - Proper error handling with descriptive messages
// - VM isolation per item execution
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Validate the script is not empty
	if conditionScript == "" {
		return nil, errors.New("condition script cannot be empty")
	}

	// Validate items slice is not nil
	if items == nil {
		return nil, errors.New("items slice cannot be nil")
	}

	// Execution timeout to prevent infinite loops (DoS protection)
	timeout := 5 * time.Second

	for i, item := range items {
		vm := otto.New()

		// Set up timeout mechanism using Otto's interrupt channel
		interruptChan := make(chan func(), 1)
		vm.Interrupt = interruptChan

		// Start timeout goroutine
		timeoutDone := make(chan struct{})
		go func() {
			select {
			case <-time.After(timeout):
				interruptChan <- func() {
					panic(ErrExecutionInterrupted)
				}
			case <-timeoutDone:
				return
			}
		}()

		// Create a deep copy of the item to prevent modification of original data
		itemCopy := make(map[string]interface{}, len(item))
		for k, v := range item {
			itemCopy[k] = v
		}

