		err := vm.Set("item", itemCopy)
		if err != nil {
			close(timeoutDone)
			return nil, fmt.Errorf("failed to set item variable at index %d: %w", i, err)
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)
		close(timeoutDone) // Stop the timeout goroutine

		if err != nil {
			// Check if it's a timeout error
			if errors.Is(err, ErrExecutionInterrupted) || err.Error() == "execution interrupted" {
				return nil, fmt.Errorf("script execution timeout at index %d (limit: %v)", i, timeout)
			}
