		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean at index %d: %w", i, err)
		}

		if boolResult {
			// Append the original item, not the copy
			result = append(result, item)
		}
	}

	return result, nil
}

