import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems filters items based on a JavaScript condition script.
// The script is executed for each item with the item available as a global variable named 'item'.
// Only items for which the script evaluates to a truthy value are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var filteredItems []map[string]interface{}

	for _, item := range items {
		// Create a new Otto VM for each item to ensure isolation
		vm := otto.New()

		// Set the item as a global variable in the JavaScript environment
		err := vm.Set("item", item)
		if err != nil {
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Execute the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute script: %w", err)
		}

		// Convert the result to a boolean
		result, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert result to boolean: %w", err)
		}

		// If the condition is true, add the item to the filtered results
		if result {
			filteredItems = append(filteredItems, item)
		}
	}

	return filteredItems, nil
}

func main() {
	// Example data items
	items := []map[string]interface{}{
		{"name": "Alice", "age": 25, "active": true},
		{"name": "Bob", "age": 30, "active": false},
		{"name": "Charlie", "age": 35, "active": true},
		{"name": "Diana", "age": 28, "active": true},
	}

	// Example 1: Filter active users
	fmt.Println("Example 1: Filter active users")
	activeUsers, err := FilterItems("item.active === true", items)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Active users: %d\n", len(activeUsers))
	for _, user := range activeUsers {
		fmt.Printf("  - %s (age: %v)\n", user["name"], user["age"])
	}

	// Example 2: Filter users older than 30
	fmt.Println("\nExample 2: Filter users older than 30")
	olderUsers, err := FilterItems("item.age > 30", items)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Users older than 30: %d\n", len(olderUsers))
	for _, user := range olderUsers {
		fmt.Printf("  - %s (age: %v)\n", user["name"], user["age"])
	}

	// Example 3: Filter users whose name starts with 'A' or 'C'
	fmt.Println("\nExample 3: Filter users whose name starts with 'A' or 'C'")
	nameFiltered, err := FilterItems("item.name.toString().startsWith('A') || item.name.toString().startsWith('C')", items)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Users with name starting with A or C: %d\n", len(nameFiltered))
	for _, user := range nameFiltered {
		fmt.Printf("  - %s (age: %v)\n", user["name"], user["age"])
	}
}

